messages.content:
This is a missed-optimization in InstCombine.

The following program reveals the missed optimization.
The source program is
```llvm
declare void @use(float)

define float @fabs_fneg_multi_use(float %x) {
  %neg = fneg float %x
  call void @use(float %neg)
  %fabs = call float @llvm.fabs.f32(float %neg)
  ret float %fabs
}

; Function Attrs: nocallback nofree nosync nounwind speculatable willreturn memory(none)
declare float @llvm.fabs.f32(float) #0

attributes #0 = { nocallback nofree nosync nounwind speculatable willreturn memory(none) }

```

However, current LLVM cannot optimize the source program. The expected optimized program is
```llvm
declare void @use(float)

define float @fabs_fneg_multi_use(float %x) {
  %neg = fneg float %x
  call void @use(float %neg)
  %fabs = call float @llvm.fabs.f32(float %x)
  ret float %fabs
}

; Function Attrs: nocallback nosync nounwind speculatable willreturn memory(none)
declare float @llvm.fabs.f32(float) #0

attributes #0 = { nocallback nosync nounwind speculatable willreturn memory(none) }

```
Please modify the following code in llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp:InstCombinerImpl::visitCallInst to implement the missed optimization:
```cpp
      return replaceOperand(*II, 0, ConstantFP::get(Mag->getType(), PosMagC));
    }

    // Peek through changes of magnitude's sign-bit. This call rewrites those:
    // copysign (fabs X), Sign --> copysign X, Sign
    // copysign (fneg X), Sign --> copysign X, Sign
    if (match(Mag, m_FAbs(m_Value(X))) || match(Mag, m_FNeg(m_Value(X))))
      return replaceOperand(*II, 0, X);

    break;
  }
  case Intrinsic::fabs: {
    Value *Cond, *TVal, *FVal;
    if (match(II->getArgOperand(0),
              m_Select(m_Value(Cond), m_Value(TVal), m_Value(FVal)))) {
      // fabs (select Cond, TrueC, FalseC) --> select Cond, AbsT, AbsF
      if (isa<Constant>(TVal) || isa<Constant>(FVal)) {
        CallInst *AbsT = Builder.CreateCall(II->getCalledFunction(), {TVal});
        CallInst *AbsF = Builder.CreateCall(II->getCalledFunction(), {FVal});
        SelectInst *SI = SelectInst::Create(Cond, AbsT, AbsF);
        FastMathFlags FMF1 = II->getFastMathFlags();
        FastMathFlags FMF2 =
            cast<SelectInst>(II->getArgOperand(0))->getFastMathFlags();
        FMF2.setNoSignedZeros(false);
        SI->setFastMathFlags(FMF1 | FMF2);
        return SI;
      }
      // fabs (select Cond, -FVal, FVal) --> fabs FVal
      if (match(TVal, m_FNeg(m_Specific(FVal))))
        return replaceOperand(*II, 0, FVal);
      // fabs (select Cond, TVal, -TVal) --> fabs TVal
      if (match(FVal, m_FNeg(m_Specific(TVal))))
        return replaceOperand(*II, 0, TVal);
    }

    Value *Magnitude, *Sign;
```

## Instructions for Fixing ##

Your response is for a formal code review and MUST strictly follow the structure below. Use the exact Markdown headings provided.

---

### 1. Analyze
**Content**: Provide a deep analysis of the missed optimization. Explain the "what" (what is the issue), the "why" (why does it happen in the current code), and the "impact" (what is the performance or correctness impact).

### 2. Propose a Patch
**Content**: Describe your proposed changes at a conceptual level. Explain the logic behind your fix and why it is the correct approach according to LLVM's coding standards.

### 3. Verify
**Content**: Walk through the execution of the provided test program with your patch applied. Explain how the new code path handles the case correctly and achieves the desired optimization.

### 4. Submit
**Content**: Provide the complete and final source code for the file that needs to be changed.
*   The code must be a single, self-contained block.
*   The code must be the full file content, not a diff or a snippet.
*   Enclose the code within a ```cpp ... ``` Markdown block.

---
Please make sure the answer includes the prefix:
```cpp
      return replaceOperand(*II, 0, ConstantFP::get(Mag->getType(), PosMagC));
    }

